parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const submissionId = body.idempotency_key || `sub_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
const submission = {
  submission_id: submissionId,
  first_name: body.first_name || '',
  last_name: body.last_name || '',
  email: (body.email || '').toLowerCase().trim(),
  phone: String(body.phone || '').replace(/\D/g, ''),
  state: body.state || '',
  role: body.role || 'parent',
  coverage_accident: body.coverage_accident || false,
  coverage_hospital_indemnity: body.coverage_hospital_indemnity || false,
  athlete_name: body.athlete_name || '',
  athlete_age: body.athlete_age || null,
  sport: body.sport || '',
  notes: body.notes || '',
  utm_source: body.utm_source || '',
  utm_campaign: body.utm_campaign || '',
  tracking_code: body.pk || body.tracking_code || '',
  submission_payload: body
};
if (!submission.email && !submission.first_name) throw new Error('Missing required fields');
return [{ json: submission }];

